const payload = $json.body ?? $json;
const transcript = payload.transcript || payload.message || payload.text || payload.call?.transcript || payload.data?.transcript || '';
const from = payload.from || payload.phone || payload.caller || payload.call?.from_number || 'demo-caller';
const callId = payload.call_id || payload.callId || payload.call?.id || `demo-${Date.now()}`;
return [{ json: { rawPayload: payload, callId: String(callId), callerPhone: String(from), transcript: String(transcript).trim() } }];

const menu = [
  { id: 'turkey_6', name: 'Turkey Breast', size: '6 inch', category: 'sub', price: 6.99, keywords: ['turkey'], upsell: 'Make it a combo with chips and a fountain drink for 3.99 more.' },
  { id: 'turkey_12', name: 'Turkey Breast', size: 'footlong', category: 'sub', price: 11.99, keywords: ['turkey'], upsell: 'Add cookies for the group while the sandwiches are being made.' },
  { id: 'italian_bmt_6', name: 'Italian BMT', size: '6 inch', category: 'sub', price: 7.49, keywords: ['italian', 'bmt'], upsell: 'Make it a combo with chips and a fountain drink for 3.99 more.' },
  { id: 'italian_bmt_12', name: 'Italian BMT', size: 'footlong', category: 'sub', price: 12.99, keywords: ['italian', 'bmt'], upsell: 'Add double meat for a heartier meal.' },
  { id: 'chicken_6', name: 'Rotisserie Chicken', size: '6 inch', category: 'sub', price: 7.99, keywords: ['chicken', 'rotisserie'], upsell: 'Make it a combo with chips and a fountain drink for 3.99 more.' },
  { id: 'steak_6', name: 'Steak and Cheese', size: '6 inch', category: 'sub', price: 8.49, keywords: ['steak', 'cheese'], upsell: 'Add double cheese or make it a combo.' },
  { id: 'chopped_salad', name: 'Chopped Turkey Salad', size: 'regular', category: 'salad', price: 8.99, keywords: ['salad'], upsell: 'Add bottled water for 1.99.' },
  { id: 'chips', name: 'Chips', size: 'bag', category: 'side', price: 1.79, keywords: ['chips'], upsell: 'Add a fountain drink.' },
  { id: 'cookie', name: 'Chocolate Chip Cookie', size: 'each', category: 'side', price: 0.99, keywords: ['cookie'], upsell: 'Add two more cookies for the table.' },
  { id: 'drink', name: 'Fountain Drink', size: 'regular', category: 'drink', price: 2.49, keywords: ['drink', 'soda', 'coke'], upsell: 'Upgrade to a large drink.' }
];

const text = ($json.transcript || '').toLowerCase();
const intent = /book|reserve|reservation|table|party of/.test(text)
  ? 'reservation'
  : /open|still taking|closed|hours|missed|call back/.test(text)
    ? 'missed_call_recovery'
    : /order|pickup|delivery|footlong|sandwich|sub|meal|salad|turkey|italian|steak|chicken/.test(text)
      ? 'order'
      : 'menu_help';

if (intent === 'reservation') {
  const partyMatch = text.match(/\b(for|party of)\s+(one|two|three|four|five|six|seven|eight|\d+)/);
  const timeMatch = text.match(/\b(?:at|around)\s+(\d{1,2})(?::(\d{2}))?\s*(am|pm)?/);
  const partyMap = { one: 1, two: 2, three: 3, four: 4, five: 5, six: 6, seven: 7, eight: 8 };
  const partySize = partyMatch ? Number(partyMap[partyMatch[2]] || partyMatch[2]) : 2;
  const requestedTime = timeMatch ? `${timeMatch[1]}${timeMatch[2] ? `:${timeMatch[2]}` : ':00'} ${(timeMatch[3] || 'PM').toUpperCase()}` : 'next available';
  const reply = `I can help with that. I have a table for ${partySize} at ${requestedTime}. May I confirm the name and phone number for the reservation?`;
  return [{ json: { callId: $json.callId, callerPhone: $json.callerPhone, transcript: $json.transcript, intent, reply, reservation: { partySize, requestedTime }, subtotal: 0, staffSummary: `Reservation lead: party of ${partySize}, requested ${requestedTime}. Agent asked for name and confirmation.` } }];
}

if (intent === 'missed_call_recovery') {
  const reply = 'Yes, we are still taking pickup orders. I can take the order now, quote the estimated total, and send it to the staff line for confirmation.';
  return [{ json: { callId: $json.callId, callerPhone: $json.callerPhone, transcript: $json.transcript, intent, reply, subtotal: 0, staffSummary: 'Missed-call recovery: caller asked whether orders are still open. Agent invited a pickup order.' } }];
}

if (intent === 'menu_help') {
  const reply = 'Popular phone orders are Turkey Breast, Italian BMT, Steak and Cheese, Rotisserie Chicken, and chopped salads. I can also make any sandwich a meal with chips and a fountain drink.';
  return [{ json: { callId: $json.callId, callerPhone: $json.callerPhone, transcript: $json.transcript, intent, reply, subtotal: 0, staffSummary: 'Menu help call: agent answered options and offered meal conversion.' } }];
}

const wantsFootlong = /footlong|12|twelve/.test(text);
const quantityMatch = text.match(/\b(two|three|four|five|six|\d+)\b/);
const quantityMap = { two: 2, three: 3, four: 4, five: 5, six: 6 };
const quantity = quantityMatch ? Number(quantityMap[quantityMatch[1]] || quantityMatch[1]) : 1;
let matches = menu.filter(item => item.keywords.some(keyword => text.includes(keyword)));
if (wantsFootlong) {
  matches = matches.map(item => menu.find(candidate => candidate.name === item.name && candidate.size === 'footlong') || item);
}
const unique = Array.from(new Map(matches.map(item => [item.id, item])).values());
const items = (unique.length ? unique : [menu.find(item => item.id === 'turkey_6')]).map(item => ({ ...item, quantity }));
const subtotal = items.reduce((sum, item) => sum + item.price * item.quantity, 0);
const hasSide = items.some(item => ['side', 'drink'].includes(item.category));
const primary = items.find(item => item.category === 'sub' || item.category === 'salad') || items[0];
const upsell = hasSide ? primary.upsell : 'Would you like to make those meals with chips and fountain drinks for 3.99 each?';
const itemList = items.map(item => `${item.quantity} ${item.name} ${item.size} ($${item.price.toFixed(2)})`).join(', ');
const reply = `Got it: ${itemList} for pickup. Estimated subtotal is $${subtotal.toFixed(2)} before tax. ${upsell}`;
return [{ json: { callId: $json.callId, callerPhone: $json.callerPhone, transcript: $json.transcript, intent, reply, matchedItems: items, subtotal: Number(subtotal.toFixed(2)), upsellOffered: upsell, staffSummary: `Pickup order draft: ${itemList}. Subtotal $${subtotal.toFixed(2)} before tax. Upsell offered: ${upsell}` } }];
